import React from 'react';
import { useAuth } from '../../context/AuthContext';
import { useLocation, NavLink } from 'react-router-dom';
import './Header.css';

const PAGE_TITLES = {
  '/dashboard':  '📊 Dashboard',
  '/attendance': '⏱ Pontaj',
  '/leaves':     '🏖 Concedii',
  '/salary':     '💰 Salarii',
  '/employees':  '👥 Angajați',
  '/shifts':     '📅 Schimburi',
  '/reports':    '📈 Rapoarte',
  '/profile':    '👤 Profil',
};

const Header = ({ onMenuClick }) => {
  const { currentUser, logout } = useAuth();
  const location = useLocation();
  const title = PAGE_TITLES[location.pathname] || 'Chain HR';

  return (
    <header className="header">
      <div className="header-left">
        <button className="header-menu-btn" onClick={onMenuClick} aria-label="Toggle menu">
          ☰
        </button>
        <h1 className="header-title">{title}</h1>
      </div>
      <div className="header-right">
        <span className="header-greeting">Bun venit, <strong>{currentUser?.firstName}</strong></span>
        <NavLink to="/profile" className="header-avatar">
          {currentUser?.firstName?.[0]}{currentUser?.lastName?.[0]}
        </NavLink>
        <button className="header-logout" onClick={logout} title="Deconectare">⏻</button>
      </div>
    </header>
  );
};

export default Header;
